+        let value = term.value.trim();
+        if value.is_empty() {
+            return Ok(Box::new(BooleanQuery::new(vec![])));
+        }
+
+        let target_fields: Vec<FieldKind> = match term.field {
+            Some(f) => vec![f],
+            None => vec![FieldKind::Name, FieldKind::Path],
+        };
+
+        let mut clauses = Vec::new();
+        for field in target_fields {
